def recommend_qml_algorithm(task, constraints):
    """
    Recommend a QML algorithm based on task and constraints.

    Args:
        task: 'classification', 'optimization', 'regression', 'generation'
        constraints: dict with keys like 'nisq_compatible', 'requires_speedup'

    Returns:
        Recommended algorithm and reasoning
    """
    nisq = constraints.get('nisq_compatible', True)

    recommendations = {
        'classification': {
            True: ('VQC or Quantum Kernel SVM', 'Variational classifiers work on NISQ devices'),
            False: ('HHL-based classifier', 'Requires fault-tolerant quantum computer')
        },
        'optimization': {
            True: ('QAOA', 'Designed for combinatorial optimization on NISQ'),
            False: ('Quantum Annealing', 'May require specialized hardware')
        },
        'regression': {
            True: ('Variational Quantum Regressor', 'Adaptable to noisy hardware'),
            False: ('Quantum Linear Regression', 'Requires error correction')
        },
        'generation': {
            True: ('Quantum Circuit Born Machine', 'Generative model for NISQ'),
            False: ('Quantum Boltzmann Machine', 'Better with error correction')
        }
    }

    if task in recommendations:
        algo, reason = recommendations[task][nisq]
        return f"Recommended: {algo}\nReason: {reason}"
    else:
        return "Unknown task type"

# Test cases
print(recommend_qml_algorithm('classification', {'nisq_compatible': True}))
print()
print(recommend_qml_algorithm('optimization', {'nisq_compatible': True}))
print()
print(recommend_qml_algorithm('regression', {'nisq_compatible': False}))
